<template>
  <div>
    <div v-if="$route.name === 'add' || loadStatus === 'success'">
      <h3 style="margin-left: 4px;">基本信息</h3>
      <a-card class="acard" style="width: 100%; border-radius: 12px; min-height: 100px; padding: 0px 0px; margin-bottom : 20px;">
        <a-list>
          <a-list-item>
            <ListItem label="活动名称" type="input" v-model="form.voteName" placeholder="请输入活动名称">
            </ListItem>
          </a-list-item>
          <a-list-item>
            <ListItem label="主办单位" type="input" v-model="form.organizer" placeholder="请输入主办单位">
            </ListItem>
          </a-list-item>
          <!-- <a-list-item>
            <ListItem label="活动开始时间" type="vantDateTimePicker" v-model="startTime">
            </ListItem>
          </a-list-item> -->
          <a-list-item>
            <ListItem label="去除最高分和最低分" type="switch" v-model="form.removeExtreme">
            </ListItem>
          </a-list-item>
        </a-list>
      </a-card>
      <!-- <h3 style="margin-left: 4px;">评分公开</h3>
      <a-card class="acard" style="width: 100%; border-radius: 12px; min-height: 100px; padding: 0px 0px;">
        <a-list>
          <a-list-item>
            <ListItem label="评分公开" type="switch" v-model="publicData">
            </ListItem>
          </a-list-item>
        </a-list>
      </a-card> -->
      <a-button type="primary" style="width: 100%; height: 48px; margin-top: 16px; font-size: 24px;" @click="save">
        {{ this.$route.name === 'detailConfig' ? '修改' : this.$route.name === 'add' ? '新建' : '保存' }}
      </a-button>
    </div>
    <span v-if="loadStatus === 'failed'">该投票不存在或被隐藏，请 <a @click="$router.push({ name: 'list' })">点此</a> 返回首页</span>
  </div>
</template>
<script>
import ListItem from '@/components/ListItem.vue'
import { voteBasicConfigurationDetail, updateVoteConfig, addVoteConfig } from '@/api/voteBasicConfiguration'
export default {
  components: { ListItem },
  data() {
    return {
      loadStatus: '',
      publicData: false,
      form: {
        voteName: '',
        coverImage: '',
        organizer: '',
        removeExtreme: false,
        createdBy: '',
        description: '',
      },
    }
  },
  mounted() {
    this.loadData()
  },
  watch: {
    '$route.params.id'(newId, oldId) {
      if (newId !== oldId) {
        this.loadData()
      }
    },
  },
  methods: {
    loadData() {
      if (this.$route.name === 'detailConfig') {
        this.loadStatus = 'loading'
        voteBasicConfigurationDetail(this.$route.params).then(res => {
          if (res) {
            this.form = res
            this.loadStatus = 'success'
          } else {
            this.loadStatus = 'failed'
          }
        })
      } else if (this.$route.name === 'add') {
        this.loadStatus = 'add'
      }
    },
    formatDate(date) {
      return `${date.getFullYear()}-${date.getMonth() + 1}-${date.getDate()}`
    },
    save() {
      if (this.$route.name === 'detailConfig') {
        updateVoteConfig(this.$route.params.id, this.form).then(res => {
          this.$message.success('已修改')
          this.$router.push({
            name: 'detail',
            params: {
              id: this.$route.params.id,
            },
          })
        })
      } else if (this.$route.name === 'add') {
        addVoteConfig(this.form).then(res => {
          this.$message.success('已添加')
          this.$router.push({ name: 'list' })
        })
      }
    },
  },
}
</script>
<style lang="less" scoped>
::v-deep .ant-card-body {
  padding: 0px !important;
}
::v-deep .van-cell__title {
  span {
    color: #333;
    font-size: 20px;
  }
}
::v-deep .van-field__control, .van-cell__value {
  font-size: 20px;
}
// ::v-deep .acard:first-child {
//   border-width: 10px 0 !important;
// }
::v-deep .ant-list-item {
  padding: 12px;
  font-size: 16px;
}
</style>
